import{_ as e,o as a,c as r,ae as i}from"./chunks/framework.CY_fclge.js";const u=JSON.parse('{"title":"Kernel Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"kernel/Benchmarks.md","filePath":"kernel/Benchmarks.md"}'),d={name:"kernel/Benchmarks.md"};function l(s,t,o,n,c,h){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="kernel-benchmarks" tabindex="-1">Kernel Benchmarks <a class="header-anchor" href="#kernel-benchmarks" aria-label="Permalink to &quot;Kernel Benchmarks&quot;">​</a></h1><h2 id="benchmark-overview" tabindex="-1">Benchmark Overview <a class="header-anchor" href="#benchmark-overview" aria-label="Permalink to &quot;Benchmark Overview&quot;">​</a></h2><p>This suite validates a single systems claim:</p><ul><li>Public-path recomputation should be bounded by dependency complexity (<code>k</code>), not dataset size (<code>n</code>).</li><li>Secret-path overhead must be measurable, bounded, and continuously improved without changing DSL semantics.</li></ul><h2 id="performance-phases-closed-status" tabindex="-1">Performance Phases (Closed Status) <a class="header-anchor" href="#performance-phases-closed-status" aria-label="Permalink to &quot;Performance Phases (Closed Status)&quot;">​</a></h2><p>The kernel now has three completed performance phases:</p><table tabindex="0"><thead><tr><th>Phase</th><th>What Closed</th><th>Latest Closure Signal</th></tr></thead><tbody><tr><td>Phase 1</td><td>Batch write viability + lightweight journal hygiene</td><td>Stable <code>14ms-20ms</code> batch writes per 100-item chunk, practical ceiling around <code>137,300</code> items before V8 heap residency became the limiter.</td></tr><tr><td>Phase 2</td><td>Bounded residency + columnar secret vector corpus</td><td>Columnar secret chunks validated, <code>Float32Array</code> payload round-trip confirmed, and the 100k encrypted leaf-write microbenchmark reached <code>1886 vps</code> with roughly <code>122MB</code> post-GC heap.</td></tr><tr><td>Phase 3</td><td>Exact baseline + IVF sidecar search</td><td>On a realistic chunk-coherent corpus, <code>100k</code> vectors now search at <code>3.32s p95</code> with <code>recall@10 = 1.000</code>, <code>18.4</code> chunks/query, and <code>23.2x</code> speedup over exact scan.</td></tr></tbody></table><h2 id="phase-closure-summary" tabindex="-1">Phase Closure Summary <a class="header-anchor" href="#phase-closure-summary" aria-label="Permalink to &quot;Phase Closure Summary&quot;">​</a></h2><h3 id="phase-1-batch-write-path-and-journal-discipline" tabindex="-1">Phase 1 | Batch Write Path and Journal Discipline <a class="header-anchor" href="#phase-1-batch-write-path-and-journal-discipline" aria-label="Permalink to &quot;Phase 1 | Batch Write Path and Journal Discipline&quot;">​</a></h3><p>Benchmarks:</p><ul><li><code>tests/Fase.1GB.js</code></li><li><code>tests/Benchmarks/Fase.1.Final.BenchmarkReport.js</code></li></ul><p>What Phase 1 proved:</p><ul><li>The batch write path remained stable deep into the run instead of degrading quadratically.</li><li><code>commitIndexedBatch()</code> no longer retained full batch payloads in <code>_memories</code>; audit entries stayed lightweight.</li><li>The practical ceiling was live V8 heap residency, not write-path collapse or journal duplication.</li></ul><p>Key closure numbers:</p><ul><li>Typical batch latency: <code>14ms-20ms</code> per 100-item chunk</li><li>Practical ceiling: <code>~137,300</code> items before heap OOM</li><li>Peak heap region observed: <code>~1660MB</code></li></ul><h3 id="phase-2-bounded-residency-and-secret-vector-storage" tabindex="-1">Phase 2 | Bounded Residency and Secret Vector Storage <a class="header-anchor" href="#phase-2-bounded-residency-and-secret-vector-storage" aria-label="Permalink to &quot;Phase 2 | Bounded Residency and Secret Vector Storage&quot;">​</a></h3><p>Benchmarks:</p><ul><li><code>tests/Benchmarks/benchmark.vector-corpus.ts</code></li><li><code>tests/Benchmarks/benchmark-100.ts</code></li></ul><p>What Phase 2 closed:</p><ul><li>Secret vector corpora now write as chunked columnar envelopes instead of tree-shaped JS payloads.</li><li>Chunk reads come back as <code>Float32Array</code> payloads, not <code>Array.from()</code> materializations.</li><li>The write path moved from “heap residency risk” to a stable, disk-backed bounded-residency model.</li></ul><p>Key closure signals:</p><ul><li><code>benchmark.vector-corpus.ts</code>: <code>columnarWrites &gt; 0</code>, <code>Float32Array</code> payload confirmed, chunk-read heap delta <code>~2.7MB</code></li><li><code>benchmark-100.ts</code> (leaf-write microbenchmark): <code>100k</code> encrypted vectors in <code>0.9min</code>, <code>1886 vps</code>, <code>~122MB</code> post-GC heap</li></ul><h3 id="phase-3-exact-search-ivf-sidecar" tabindex="-1">Phase 3 | Exact Search + IVF Sidecar <a class="header-anchor" href="#phase-3-exact-search-ivf-sidecar" aria-label="Permalink to &quot;Phase 3 | Exact Search + IVF Sidecar&quot;">​</a></h3><p>Benchmarks:</p><ul><li><code>tests/Fase.3.0.search-exact.test.ts</code></li><li><code>tests/Benchmarks/benchmark.search-exact-scale.ts</code></li><li><code>tests/Benchmarks/benchmark.ivf-vs-exact.ts</code></li><li><code>tests/Benchmarks/benchmark.ivf-tuning.ts</code></li></ul><p>What Phase 3 closed:</p><ul><li><code>searchExact()</code> established a correctness baseline before approximate search.</li><li>IVF became a persistent sidecar outside the kernel log, with explicit <code>buildVectorIndex()</code> and <code>searchVector()</code> APIs.</li><li>Candidate-cap tuning, chunk-aware build, and realistic-vs-hostile corpus separation made ANN behavior measurable instead of anecdotal.</li></ul><p>Official <code>100k</code> closure profiles:</p><table tabindex="0"><thead><tr><th>Corpus</th><th style="text-align:right;">Exact p95</th><th style="text-align:right;">IVF p95</th><th style="text-align:right;">Recall@10</th><th style="text-align:right;">Chunks / Query</th><th style="text-align:right;">Speedup</th></tr></thead><tbody><tr><td><code>chunk_coherent</code> (realistic)</td><td style="text-align:right;"><code>77129.34ms</code></td><td style="text-align:right;"><code>3318.42ms</code></td><td style="text-align:right;"><code>1.000</code></td><td style="text-align:right;"><code>18.40</code></td><td style="text-align:right;"><code>23.2x</code></td></tr><tr><td><code>legacy_fragmented</code> (hostile)</td><td style="text-align:right;"><code>166603.63ms</code></td><td style="text-align:right;"><code>19353.27ms</code></td><td style="text-align:right;"><code>1.000</code></td><td style="text-align:right;"><code>97.60</code></td><td style="text-align:right;"><code>8.6x</code></td></tr></tbody></table><p>Interpretation:</p><ul><li>The realistic corpus is now the README-grade claim.</li><li>The hostile corpus remains part of the suite to document worst-case chunk fragmentation honestly.</li><li>The remaining Phase 3 caveat is build cost for large IVF indexes; search behavior itself is now closed for the realistic profile.</li></ul><h2 id="benchmark-matrix" tabindex="-1">Benchmark Matrix <a class="header-anchor" href="#benchmark-matrix" aria-label="Permalink to &quot;Benchmark Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>File</th><th>What It Proves</th></tr></thead><tbody><tr><td>#5 Sustained Mutation</td><td><code>tests/Benchmarks/benchmark.5.sustained-mutation.test.ts</code></td><td>Throughput stability over long mutation streams; p95 drift over time windows.</td></tr><tr><td>#6 Fan-Out Sensitivity</td><td><code>tests/Benchmarks/benchmark.6.fanout-sensitivity.test.ts</code></td><td>Latency behavior as fan-out grows, with constant derivation complexity <code>k</code>.</td></tr><tr><td>#7 Cold vs Warm</td><td><code>tests/Benchmarks/benchmark.7.cold-warm-profiles.test.ts</code></td><td>Separation of cold setup cost vs warm and steady-state runtime.</td></tr><tr><td>#8 Explain Overhead</td><td><code>tests/Benchmarks/benchmark.8.explain-overhead.test.ts</code></td><td>Observability overhead of <code>explain(path)</code> vs baseline mutation/read loops.</td></tr><tr><td>#9 Secret-Scope Impact</td><td><code>tests/Benchmarks/benchmark.9.secret-scope-impact.test.ts</code></td><td>Public vs secret latency envelope under equivalent workloads.</td></tr><tr><td>#10 Push vs Pull</td><td><code>tests/Benchmarks/benchmark.10.push-vs-pull.test.ts</code></td><td>Isolation of write-only (<code>push</code>) and first-read-after-write (<code>pull</code>) in eager vs lazy modes.</td></tr><tr><td>#11 Secret Push vs Pull</td><td><code>tests/Benchmarks/benchmark.11.secret-push-vs-pull.test.ts</code></td><td>Secret/public split of push vs pull; confirms secret-path cost structure after chunking/cache refactors.</td></tr><tr><td>Regression Gate</td><td><code>tests/Benchmarks/benchmark.regression-gate.test.ts</code></td><td>CI pass/fail checks for p95 latency, <code>k</code> complexity bound, and stealth masking correctness.</td></tr><tr><td>Vector Corpus</td><td><code>tests/Benchmarks/benchmark.vector-corpus.ts</code></td><td>Validates columnar secret vector chunks, typed payload round-trip, and chunk-read heap discipline.</td></tr><tr><td>Exact Search Scale</td><td><code>tests/Benchmarks/benchmark.search-exact-scale.ts</code></td><td>Shows how exact vector search scales by chunk count and where decrypted-chunk cache thrash begins.</td></tr><tr><td>IVF vs Exact</td><td><code>tests/Benchmarks/benchmark.ivf-vs-exact.ts</code></td><td>Compares exact scan and IVF sidecar on the same corpus.</td></tr><tr><td>IVF Tuning</td><td><code>tests/Benchmarks/benchmark.ivf-tuning.ts</code></td><td>Sweeps <code>nlist</code>, <code>nprobe</code>, and candidate caps; now also supports realistic and hostile corpus generators.</td></tr></tbody></table><h2 id="latest-verified-local-runs" tabindex="-1">Latest Verified Local Runs <a class="header-anchor" href="#latest-verified-local-runs" aria-label="Permalink to &quot;Latest Verified Local Runs&quot;">​</a></h2><p>Machine: <code>Suis-MacBook-Air</code><br> Run context: isolated local runs on <code>April 18-19, 2026</code></p><p>Notes:</p><ul><li>The tables below were taken from isolated runs on the current branch.</li><li><code>#9</code> and <code>#11</code> are the most sensitive to ambient machine load, so they should be read as performance envelopes, not hard SLAs.</li><li>The historical pre-5.4/5.5 secret baseline still lives in <code>tests/Benchmarks/BASELINE-5-FINAL.md</code>.</li></ul><h3 id="_5-throughput-under-sustained-mutation" tabindex="-1">#5 Throughput Under Sustained Mutation <a class="header-anchor" href="#_5-throughput-under-sustained-mutation" aria-label="Permalink to &quot;#5 Throughput Under Sustained Mutation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metric</th><th style="text-align:right;">Value (ms)</th></tr></thead><tbody><tr><td>p50</td><td style="text-align:right;">0.0074</td></tr><tr><td>p95</td><td style="text-align:right;">0.0109</td></tr><tr><td>p99</td><td style="text-align:right;">0.0165</td></tr><tr><td>max</td><td style="text-align:right;">0.7165</td></tr></tbody></table><p>Windowed p95 drift: <code>-40.97%</code> (end window vs start window).</p><p>Interpretation:</p><ul><li>No upward drift under sustained updates.</li><li>Throughput remains stable as history grows.</li></ul><h3 id="_6-fan-out-sensitivity-curves" tabindex="-1">#6 Fan-Out Sensitivity Curves <a class="header-anchor" href="#_6-fan-out-sensitivity-curves" aria-label="Permalink to &quot;#6 Fan-Out Sensitivity Curves&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Fanout</th><th style="text-align:right;">k</th><th style="text-align:right;">p50 (ms)</th><th style="text-align:right;">p95 (ms)</th><th style="text-align:right;">p99 (ms)</th></tr></thead><tbody><tr><td style="text-align:right;">10</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0128</td><td style="text-align:right;">0.0204</td><td style="text-align:right;">0.0939</td></tr><tr><td style="text-align:right;">100</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0086</td><td style="text-align:right;">0.0148</td><td style="text-align:right;">0.0290</td></tr><tr><td style="text-align:right;">500</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0081</td><td style="text-align:right;">0.0109</td><td style="text-align:right;">0.0156</td></tr><tr><td style="text-align:right;">1000</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0065</td><td style="text-align:right;">0.0082</td><td style="text-align:right;">0.0104</td></tr><tr><td style="text-align:right;">2500</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0064</td><td style="text-align:right;">0.0079</td><td style="text-align:right;">0.0132</td></tr><tr><td style="text-align:right;">5000</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0062</td><td style="text-align:right;">0.0093</td><td style="text-align:right;">0.0111</td></tr></tbody></table><p>Interpretation:</p><ul><li><code>k</code> stays constant at <code>2</code>.</li><li>Latency stays in micro-to-low-millisecond range across fanout values.</li></ul><h3 id="_7-cold-vs-warm-runtime-profiles" tabindex="-1">#7 Cold vs Warm Runtime Profiles <a class="header-anchor" href="#_7-cold-vs-warm-runtime-profiles" aria-label="Permalink to &quot;#7 Cold vs Warm Runtime Profiles&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Nodes</th><th style="text-align:right;">Cold (ms)</th><th style="text-align:right;">Warm (ms)</th><th style="text-align:right;">Steady Avg (ms)</th><th style="text-align:right;">Steady Min (ms)</th><th style="text-align:right;">Steady Max (ms)</th></tr></thead><tbody><tr><td style="text-align:right;">100</td><td style="text-align:right;">0.1715</td><td style="text-align:right;">0.0892</td><td style="text-align:right;">0.0144</td><td style="text-align:right;">0.0108</td><td style="text-align:right;">0.0907</td></tr><tr><td style="text-align:right;">1000</td><td style="text-align:right;">0.0116</td><td style="text-align:right;">0.0123</td><td style="text-align:right;">0.0066</td><td style="text-align:right;">0.0058</td><td style="text-align:right;">0.0120</td></tr><tr><td style="text-align:right;">5000</td><td style="text-align:right;">0.0135</td><td style="text-align:right;">0.0140</td><td style="text-align:right;">0.0069</td><td style="text-align:right;">0.0057</td><td style="text-align:right;">0.0155</td></tr></tbody></table><p>Interpretation:</p><ul><li>Cold penalty is isolated.</li><li>Warm/steady paths are consistently fast.</li></ul><h3 id="_8-explain-overhead-budget" tabindex="-1">#8 Explain Overhead Budget <a class="header-anchor" href="#_8-explain-overhead-budget" aria-label="Permalink to &quot;#8 Explain Overhead Budget&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th style="text-align:right;">p50 (ms)</th><th style="text-align:right;">p95 (ms)</th><th style="text-align:right;">p99 (ms)</th></tr></thead><tbody><tr><td>baseline</td><td style="text-align:right;">0.0087</td><td style="text-align:right;">0.0154</td><td style="text-align:right;">0.0370</td></tr><tr><td>with_explain</td><td style="text-align:right;">0.0141</td><td style="text-align:right;">0.0198</td><td style="text-align:right;">0.0298</td></tr></tbody></table><p><code>p95</code> overhead: <code>28.11%</code>.</p><p>Interpretation:</p><ul><li><code>explain(path)</code> adds bounded overhead while preserving traceability.</li><li>Absolute overhead remains sub-millisecond, making it production-safe for real-time auditing.</li></ul><h3 id="_9-secret-scope-performance-impact" tabindex="-1">#9 Secret-Scope Performance Impact <a class="header-anchor" href="#_9-secret-scope-performance-impact" aria-label="Permalink to &quot;#9 Secret-Scope Performance Impact&quot;">​</a></h3><p>Latest isolated run:</p><table tabindex="0"><thead><tr><th>Scope</th><th style="text-align:right;">p50 (ms)</th><th style="text-align:right;">p95 (ms)</th><th style="text-align:right;">p99 (ms)</th></tr></thead><tbody><tr><td>public</td><td style="text-align:right;">0.0102</td><td style="text-align:right;">0.0175</td><td style="text-align:right;">0.1177</td></tr><tr><td>secret</td><td style="text-align:right;">0.3277</td><td style="text-align:right;">0.3684</td><td style="text-align:right;">0.6566</td></tr></tbody></table><p>Interpretation:</p><ul><li>Secret path remains slower than public by design cost: crypto, stealth boundary logic, and lazy refresh/write-back.</li><li>In absolute terms, secret <code>p95</code> stays well below <code>1ms</code> for this scenario.</li><li>Compared with the March 2026 historical baseline in <code>BASELINE-5-FINAL.md</code> (<code>4.6503ms</code> secret <code>p95</code>), the current local value remains roughly <code>92%</code> lower in absolute <code>p95</code>.</li><li>Slowdown percentages still look dramatic because the public path is already extremely close to the timer floor.</li></ul><h3 id="_10-push-vs-pull-eager-vs-lazy" tabindex="-1">#10 Push vs Pull (Eager vs Lazy) <a class="header-anchor" href="#_10-push-vs-pull-eager-vs-lazy" aria-label="Permalink to &quot;#10 Push vs Pull (Eager vs Lazy)&quot;">​</a></h3><p>Selected row from the latest isolated run (<code>fanout = 5000</code>):</p><table tabindex="0"><thead><tr><th>Mode</th><th style="text-align:right;">Fanout</th><th style="text-align:right;">k</th><th style="text-align:right;">Mutation p95 (ms)</th><th style="text-align:right;">Read p95 (ms)</th></tr></thead><tbody><tr><td>eager</td><td style="text-align:right;">5000</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0036</td><td style="text-align:right;">0.0033</td></tr><tr><td>lazy</td><td style="text-align:right;">5000</td><td style="text-align:right;">2</td><td style="text-align:right;">0.0036</td><td style="text-align:right;">0.0036</td></tr></tbody></table><p>Interpretation:</p><ul><li>Both modes remain low-latency in steady-state.</li><li><code>push</code> and <code>first-read-after-write</code> stay measurable as separate costs, which is the benchmark&#39;s main purpose.</li><li>Single-run outliers can appear at lower fanouts, so this benchmark is best read as a shape test rather than a one-number SLA.</li></ul><h3 id="_11-secret-push-vs-pull-shared-v3-key-cache-lazy-recompute" tabindex="-1">#11 Secret Push vs Pull (Shared v3 Key Cache + Lazy Recompute) <a class="header-anchor" href="#_11-secret-push-vs-pull-shared-v3-key-cache-lazy-recompute" aria-label="Permalink to &quot;#11 Secret Push vs Pull (Shared v3 Key Cache + Lazy Recompute)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plane</th><th style="text-align:right;">Nodes</th><th style="text-align:right;">Mutation p95 (ms)</th><th style="text-align:right;">Read p95 (ms)</th></tr></thead><tbody><tr><td>public</td><td style="text-align:right;">100</td><td style="text-align:right;">0.0087</td><td style="text-align:right;">0.0131</td></tr><tr><td>secret</td><td style="text-align:right;">100</td><td style="text-align:right;">0.0406</td><td style="text-align:right;">0.4040</td></tr><tr><td>public</td><td style="text-align:right;">300</td><td style="text-align:right;">0.0045</td><td style="text-align:right;">0.0058</td></tr><tr><td>secret</td><td style="text-align:right;">300</td><td style="text-align:right;">0.0281</td><td style="text-align:right;">0.1945</td></tr><tr><td>public</td><td style="text-align:right;">600</td><td style="text-align:right;">0.0043</td><td style="text-align:right;">0.0048</td></tr><tr><td>secret</td><td style="text-align:right;">600</td><td style="text-align:right;">0.0252</td><td style="text-align:right;">0.3084</td></tr></tbody></table><p>Slowdown ratios (secret/public p95):</p><table tabindex="0"><thead><tr><th style="text-align:right;">Nodes</th><th style="text-align:right;">Mutation slowdown x</th><th style="text-align:right;">Read slowdown x</th></tr></thead><tbody><tr><td style="text-align:right;">100</td><td style="text-align:right;">4.67x</td><td style="text-align:right;">30.84x</td></tr><tr><td style="text-align:right;">300</td><td style="text-align:right;">6.24x</td><td style="text-align:right;">33.53x</td></tr><tr><td style="text-align:right;">600</td><td style="text-align:right;">5.86x</td><td style="text-align:right;">64.25x</td></tr></tbody></table><p>Interpretation:</p><ul><li>Secret mutation cost stays in low-sub-millisecond territory.</li><li>Secret read cost is still the noisiest part of the runtime because this benchmark couples crypto with lazy derivation refresh and write-back.</li><li>In absolute terms, the latest isolated run still kept secret read <code>p95</code> below <code>1ms</code> at <code>100</code> and <code>600</code> nodes, and around <code>0.35ms</code> at <code>300</code> nodes.</li></ul><h2 id="regression-and-vector-search-status" tabindex="-1">Regression and Vector Search Status <a class="header-anchor" href="#regression-and-vector-search-status" aria-label="Permalink to &quot;Regression and Vector Search Status&quot;">​</a></h2><p>Latest gates now cover both the original kernel loop and the vector-search stack:</p><ul><li><code>latency_p95</code>: ✅ kernel mutation/read loop remains in the low-millisecond envelope</li><li><code>complexity_k</code>: ✅ <code>k=2</code> remains stable across fanout and graph size tests</li><li><code>stealth_masking</code>: ✅ secret origins remain masked in <code>explain()</code></li><li><code>searchExact</code>: ✅ correctness baseline established before ANN</li><li><code>IVF realistic</code>: ✅ <code>100k</code>, <code>recall@10 = 1.000</code>, <code>IVF p95 = 3318.42ms</code></li><li><code>IVF hostile</code>: ✅ <code>100k</code>, <code>recall@10 = 1.000</code>, <code>IVF p95 = 19353.27ms</code></li></ul><h2 id="what-is-proven-now" tabindex="-1">What Is Proven Now <a class="header-anchor" href="#what-is-proven-now" aria-label="Permalink to &quot;What Is Proven Now&quot;">​</a></h2><ul><li>Public-path performance is stable and effectively bounded by small <code>k</code>.</li><li>Lazy/eager recompute modes are operational and benchmarked.</li><li>Explainability overhead is measurable and bounded.</li><li>Secret-path cost is no longer monolithic; shared v3 key reuse removed the worst cold branch-derivation penalty.</li><li>Secret reads are still the most expensive path, but they now sit in the sub-millisecond envelope for the main <code>#9</code> scenario on isolated runs.</li><li>Privacy and semantic invariants remain intact while performance work lands.</li><li>The secret vector corpus is now genuinely columnar and typed, with <code>Float32Array</code> payloads on the hot path.</li><li>Exact vector search is correct and measurable.</li><li>IVF sidecars are now part of the supported runtime story, with separate realistic and hostile closure profiles.</li></ul><h2 id="next-optimization-frontier" tabindex="-1">Next Optimization Frontier <a class="header-anchor" href="#next-optimization-frontier" aria-label="Permalink to &quot;Next Optimization Frontier&quot;">​</a></h2><ul><li>On the kernel side, the next real frontier is still separating lazy derivation refresh from full memory append/hash-chain write-back on internal recomputes.</li><li>On the vector side, the next frontier is IVF build cost and finer posting selectivity, not correctness.</li><li>That is a structural systems task, not just another round of micro-optimizations.</li></ul>',78)])])}const p=e(d,[["render",l]]);export{u as __pageData,p as default};
